import java.io.*;import java.util.*;class Main{static class AutocompleteSystem{HashMap<String,Integer> counts=new HashMap<>();String current="";AutocompleteSystem(String[] s,int[] t){for(int i=0;i<s.length;i++)counts.put(s[i],counts.getOrDefault(s[i],0)+t[i]);}List<String> input(String ch){if(ch.equals("#")){counts.put(current,counts.getOrDefault(current,0)+1);current="";return new ArrayList<>();}current+=ch;ArrayList<String> m=new ArrayList<>();for(String s:counts.keySet())if(s.startsWith(current))m.add(s);m.sort((a,b)->counts.get(a).equals(counts.get(b))?a.compareTo(b):counts.get(b)-counts.get(a));if(m.size()>3)m.subList(3,m.size()).clear();return m;}}static String format(List<String> items,boolean ok){if(!ok)return"null";StringBuilder sb=new StringBuilder("[");for(int i=0;i<items.size();i++){if(i>0)sb.append(",");sb.append("\"").append(items.get(i)).append("\"");}return sb.append("]").toString();}static String decode(String s){return s.equals("<space>")?" ":s;}public static void main(String[] a)throws Exception{List<String> raw=Arrays.asList(new String(System.in.readAllBytes()).split("\\R"));ArrayList<String> lines=new ArrayList<>();for(String s:raw){if(!s.trim().isEmpty())lines.add(s.replace("\r",""));}if(lines.isEmpty())return;int t=Integer.parseInt(lines.get(0)),idx=1;StringBuilder ans=new StringBuilder();for(int tc=0;tc<t;tc++){int q=Integer.parseInt(lines.get(idx++));AutocompleteSystem sys=null;ArrayList<String> out=new ArrayList<>();for(int i=0;i<q;i++){String line=lines.get(idx++);if(line.startsWith("C ")){int n=Integer.parseInt(line.substring(2));String[] s=new String[n];int[] tm=new int[n];for(int j=0;j<n;j++){String cur=lines.get(idx++);int p=cur.indexOf('|');tm[j]=Integer.parseInt(cur.substring(0,p));s[j]=cur.substring(p+1);}sys=new AutocompleteSystem(s,tm);out.add("null");}else out.add(format(sys.input(decode(line.substring(2))),true));}if(tc>0)ans.append("\n\n");ans.append("[").append(String.join(",",out)).append("]");}System.out.print(ans);}}
